/**
 * Unit tests for API Documentation Generator (OpenAPI 3.0)
 *
 * Tests are organised by function, covering happy paths, edge cases,
 * and the constant exports.
 */
import {
  filePathToApiPath,
  extractDynamicParams,
  extractDomain,
  parseRouteExports,
  buildRouteInfo,
  groupByDomain,
  generateOperationId,
  buildPathParameters,
  buildPathItem,
  buildTags,
  generateOpenApiSpec,
  generateSummary,
  formatSpecAsJson,
  validateSpec,
  API_DOMAINS,
  VALID_HTTP_METHODS,
  DEFAULT_CONFIG,
} from '@/lib/docs/api-doc-generator';
import type {
  RouteInfo,
  OpenApiSpec,
  ApiDomain,
  HttpMethod,
} from '@/lib/docs/api-doc-generator';

// ────────────────────────────────────────────────────────────
// Helpers
// ────────────────────────────────────────────────────────────

function makeRoute(overrides: Partial<RouteInfo> = {}): RouteInfo {
  return {
    filePath: 'src/app/api/auth/login/route.ts',
    apiPath: '/api/auth/login',
    methods: ['POST'],
    domain: 'auth',
    hasDynamicSegments: false,
    dynamicParams: [],
    ...overrides,
  };
}

// ────────────────────────────────────────────────────────────
// filePathToApiPath
// ────────────────────────────────────────────────────────────

describe('filePathToApiPath', () => {
  it('converts a basic route path', () => {
    expect(filePathToApiPath('src/app/api/auth/login/route.ts')).toBe(
      '/api/auth/login',
    );
  });

  it('handles dynamic segments', () => {
    expect(filePathToApiPath('src/app/api/users/[id]/route.ts')).toBe(
      '/api/users/{id}',
    );
  });

  it('handles nested dynamic segments', () => {
    expect(
      filePathToApiPath('src/app/api/users/[userId]/posts/[postId]/route.ts'),
    ).toBe('/api/users/{userId}/posts/{postId}');
  });

  it('handles root api route', () => {
    expect(filePathToApiPath('src/app/api/route.ts')).toBe('/api');
  });

  it('handles route.js extension', () => {
    expect(filePathToApiPath('src/app/api/health/route.js')).toBe(
      '/api/health',
    );
  });

  it('handles backslash separators (Windows paths)', () => {
    expect(filePathToApiPath('src\\app\\api\\auth\\login\\route.ts')).toBe(
      '/api/auth/login',
    );
  });
});

