// extractDynamicParams
// ────────────────────────────────────────────────────────────

describe('extractDynamicParams', () => {
  it('extracts a single param', () => {
    expect(extractDynamicParams('/api/users/{id}')).toEqual(['id']);
  });

  it('extracts multiple params', () => {
    expect(
      extractDynamicParams('/api/users/{userId}/posts/{postId}'),
    ).toEqual(['userId', 'postId']);
  });

  it('returns empty array when no params', () => {
    expect(extractDynamicParams('/api/health')).toEqual([]);
  });
});

