// ────────────────────────────────────────────────────────────
// parseRouteExports
// ────────────────────────────────────────────────────────────

describe('parseRouteExports', () => {
  it('detects export async function', () => {
    const content = `
      import { NextRequest } from 'next/server';
      export async function GET(req: NextRequest) { return new Response(); }
    `;
    expect(parseRouteExports(content)).toEqual(['GET']);
  });

  it('detects export function (no async)', () => {
    const content = `export function POST(req) { return new Response(); }`;
    expect(parseRouteExports(content)).toEqual(['POST']);
  });

  it('detects export const', () => {
    const content = `export const PUT = async (req) => { return new Response(); };`;
    expect(parseRouteExports(content)).toEqual(['PUT']);
  });

  it('detects named exports (export { })', () => {
    const content = `
      async function GET(req) {}
      async function POST(req) {}
      export { GET, POST };
    `;
    expect(parseRouteExports(content)).toEqual(['GET', 'POST']);
  });

  it('returns empty array when no methods exported', () => {
    const content = `export default function handler() {}`;
    expect(parseRouteExports(content)).toEqual([]);
  });

  it('detects multiple methods', () => {
    const content = `
      export async function GET(req) {}
      export async function POST(req) {}
      export async function DELETE(req) {}
    `;
    expect(parseRouteExports(content)).toEqual(['GET', 'POST', 'DELETE']);
  });

  it('does not match non-exported functions', () => {
    const content = `async function GET(req) { return; }`;
    expect(parseRouteExports(content)).toEqual([]);
  });

  it('handles export let', () => {
    const content = `export let PATCH = async () => {};`;
    expect(parseRouteExports(content)).toEqual(['PATCH']);
  });

  it('detects methods inside multi-line named exports', () => {
    const content = `
      export {
        GET,
        POST,
        DELETE
      };
    `;
    expect(parseRouteExports(content)).toEqual(['GET', 'POST', 'DELETE']);
  });
});

// ────────────────────────────────────────────────────────────
// buildRouteInfo
// ────────────────────────────────────────────────────────────

describe('buildRouteInfo', () => {
  it('combines all parsing correctly for a static route', () => {
    const content = `export async function POST(req) {}`;
    const info = buildRouteInfo('src/app/api/auth/login/route.ts', content);

    expect(info.filePath).toBe('src/app/api/auth/login/route.ts');
    expect(info.apiPath).toBe('/api/auth/login');
    expect(info.methods).toEqual(['POST']);
    expect(info.domain).toBe('auth');
    expect(info.hasDynamicSegments).toBe(false);
    expect(info.dynamicParams).toEqual([]);
  });

  it('handles dynamic route correctly', () => {
    const content = `
      export async function GET(req) {}
      export async function PUT(req) {}
    `;
    const info = buildRouteInfo(
      'src/app/api/users/[id]/route.ts',
      content,
    );

    expect(info.apiPath).toBe('/api/users/{id}');
    expect(info.methods).toEqual(['GET', 'PUT']);
    expect(info.hasDynamicSegments).toBe(true);
    expect(info.dynamicParams).toEqual(['id']);
  });
});

// ────────────────────────────────────────────────────────────
// groupByDomain
// ────────────────────────────────────────────────────────────

describe('groupByDomain', () => {
  it('groups routes correctly', () => {
    const routes: RouteInfo[] = [
      makeRoute({ domain: 'auth', apiPath: '/api/auth/login' }),
      makeRoute({ domain: 'auth', apiPath: '/api/auth/register' }),
      makeRoute({ domain: 'tts', apiPath: '/api/tts/generate' }),
    ];
    const groups = groupByDomain(routes);

    expect(groups).toHaveLength(2);
    expect(groups[0].name).toBe('auth');
    expect(groups[0].routeCount).toBe(2);
    expect(groups[1].name).toBe('tts');
    expect(groups[1].routeCount).toBe(1);
  });

  it('sorts domains alphabetically', () => {
    const routes: RouteInfo[] = [
      makeRoute({ domain: 'tts' }),
      makeRoute({ domain: 'auth' }),
      makeRoute({ domain: 'billing' }),
    ];
    const groups = groupByDomain(routes);
    const names = groups.map((g) => g.name);
    expect(names).toEqual(['auth', 'billing', 'tts']);
  });

  it('gives unknown domains a generic description', () => {
    const routes: RouteInfo[] = [
      makeRoute({ domain: 'foobar' }),
    ];
    const groups = groupByDomain(routes);
    expect(groups[0].description).toBe('Foobar endpoints');
  });

  it('uses known descriptions for recognised domains', () => {
    const routes: RouteInfo[] = [
      makeRoute({ domain: 'health' }),
    ];
    const groups = groupByDomain(routes);
    expect(groups[0].description).toBe('Health checks');
  });
});

