describe('generateOperationId', () => {
  it('creates id for basic path', () => {
    expect(generateOperationId('GET', '/api/auth/login')).toBe('getAuthLogin');
  });

  it('handles dynamic params', () => {
    expect(generateOperationId('POST', '/api/users/{id}')).toBe(
      'postUsersById',
    );
  });

  it('handles nested paths', () => {
    expect(
      generateOperationId('DELETE', '/api/users/{userId}/posts/{postId}'),
    ).toBe('deleteUsersByUserIdPostsByPostId');
  });

  it('lowercases the method prefix', () => {
    expect(generateOperationId('PATCH', '/api/billing/plan')).toBe(
      'patchBillingPlan',
    );
  });
});

// ────────────────────────────────────────────────────────────
// buildPathParameters
// ────────────────────────────────────────────────────────────

describe('buildPathParameters', () => {
  it('creates parameters for a single param', () => {
    const route = makeRoute({
      dynamicParams: ['id'],
      hasDynamicSegments: true,
    });
    const params = buildPathParameters(route);
    expect(params).toHaveLength(1);
    expect(params[0]).toEqual({
      name: 'id',
      in: 'path',
      required: true,
      schema: { type: 'string' },
      description: 'The id parameter',
    });
  });

  it('creates parameters for multiple params', () => {
    const route = makeRoute({
      dynamicParams: ['userId', 'postId'],
      hasDynamicSegments: true,
    });
    const params = buildPathParameters(route);
    expect(params).toHaveLength(2);
    expect(params[0].name).toBe('userId');
    expect(params[1].name).toBe('postId');
  });

  it('returns empty array when no dynamic segments', () => {
    const route = makeRoute();
    const params = buildPathParameters(route);
    expect(params).toEqual([]);
  });
});

// ────────────────────────────────────────────────────────────
// buildPathItem
// ────────────────────────────────────────────────────────────

describe('buildPathItem', () => {
  it('creates item with a single method', () => {
    const route = makeRoute({ methods: ['GET'] });
    const item = buildPathItem(route);
    expect(item).toHaveProperty('get');
    expect(item.get.operationId).toBe('getAuthLogin');
  });

  it('creates item with multiple methods', () => {
    const route = makeRoute({ methods: ['GET', 'POST', 'DELETE'] });
    const item = buildPathItem(route);
    expect(Object.keys(item)).toEqual(
      expect.arrayContaining(['get', 'post', 'delete']),
    );
  });

  it('includes parameters for dynamic routes', () => {
    const route = makeRoute({
      apiPath: '/api/users/{id}',
      methods: ['GET'],
      dynamicParams: ['id'],
      hasDynamicSegments: true,
    });
    const item = buildPathItem(route);
    expect(item.get.parameters).toHaveLength(1);
    expect(item.get.parameters?.[0].name).toBe('id');
  });

  it('omits parameters for static routes', () => {
    const route = makeRoute({ methods: ['GET'] });
    const item = buildPathItem(route);
    expect(item.get.parameters).toBeUndefined();
  });
});

