// ────────────────────────────────────────────────────────────
// generateOpenApiSpec
// ────────────────────────────────────────────────────────────

describe('generateOpenApiSpec', () => {
  const routes: RouteInfo[] = [
    makeRoute({ methods: ['GET', 'POST'], domain: 'auth' }),
    makeRoute({
      filePath: 'src/app/api/health/route.ts',
      apiPath: '/api/health',
      methods: ['GET'],
      domain: 'health',
    }),
  ];

  it('produces a complete spec structure', () => {
    const spec = generateOpenApiSpec(routes);
    expect(spec).toHaveProperty('openapi');
    expect(spec).toHaveProperty('info');
    expect(spec).toHaveProperty('servers');
    expect(spec).toHaveProperty('paths');
    expect(spec).toHaveProperty('tags');
  });

  it('uses openapi version 3.0.3', () => {
    const spec = generateOpenApiSpec(routes);
    expect(spec.openapi).toBe('3.0.3');
  });

  it('applies custom config', () => {
    const spec = generateOpenApiSpec(routes, {
      title: 'My Custom API',
      version: '5.0.0',
    });
    expect(spec.info.title).toBe('My Custom API');
    expect(spec.info.version).toBe('5.0.0');
  });

  it('applies default config when none provided', () => {
    const spec = generateOpenApiSpec(routes);
    expect(spec.info.title).toBe(DEFAULT_CONFIG.title);
    expect(spec.info.version).toBe(DEFAULT_CONFIG.version);
    expect(spec.servers[0].url).toBe(DEFAULT_CONFIG.serverUrl);
  });

  it('includes paths for all routes', () => {
    const spec = generateOpenApiSpec(routes);
    expect(Object.keys(spec.paths)).toContain('/api/auth/login');
    expect(Object.keys(spec.paths)).toContain('/api/health');
  });

  it('includes tags for all domains', () => {
    const spec = generateOpenApiSpec(routes);
    const tagNames = spec.tags.map((t) => t.name);
    expect(tagNames).toContain('auth');
    expect(tagNames).toContain('health');
  });
});

// ────────────────────────────────────────────────────────────
// generateSummary
// ────────────────────────────────────────────────────────────

describe('generateSummary', () => {
  it('counts routes, endpoints, domains correctly', () => {
    const routes: RouteInfo[] = [
      makeRoute({ methods: ['GET', 'POST'], domain: 'auth' }),
      makeRoute({
        apiPath: '/api/health',
        methods: ['GET'],
        domain: 'health',
      }),
    ];
    const summary = generateSummary(routes);
    expect(summary.totalRoutes).toBe(2);
    expect(summary.totalEndpoints).toBe(3);
    expect(summary.domains).toEqual(['auth', 'health']);
  });

  it('counts method breakdown correctly', () => {
    const routes: RouteInfo[] = [
      makeRoute({ methods: ['GET', 'POST'] }),
      makeRoute({ methods: ['GET', 'DELETE'] }),
    ];
    const summary = generateSummary(routes);
    expect(summary.methodBreakdown.GET).toBe(2);
    expect(summary.methodBreakdown.POST).toBe(1);
    expect(summary.methodBreakdown.DELETE).toBe(1);
    expect(summary.methodBreakdown.PUT).toBe(0);
  });

  it('counts dynamic vs static routes', () => {
    const routes: RouteInfo[] = [
      makeRoute({ hasDynamicSegments: false }),
      makeRoute({ hasDynamicSegments: true }),
      makeRoute({ hasDynamicSegments: true }),
    ];
    const summary = generateSummary(routes);
    expect(summary.dynamicRoutes).toBe(2);
    expect(summary.staticRoutes).toBe(1);
  });
});

