// formatSpecAsJson
// ────────────────────────────────────────────────────────────

describe('formatSpecAsJson', () => {
  const spec = generateOpenApiSpec([makeRoute()]);

  it('produces compact JSON when pretty=false', () => {
    const json = formatSpecAsJson(spec, false);
    expect(json).not.toContain('\n');
  });

  it('produces pretty JSON by default', () => {
    const json = formatSpecAsJson(spec);
    expect(json).toContain('\n');
    expect(json).toContain('  '); // 2-space indent
  });

  it('output is valid JSON', () => {
    const json = formatSpecAsJson(spec);
    expect(() => JSON.parse(json)).not.toThrow();
  });
});

// ────────────────────────────────────────────────────────────
// validateSpec
// ────────────────────────────────────────────────────────────

describe('validateSpec', () => {
  it('valid spec passes', () => {
    const spec = generateOpenApiSpec([makeRoute()]);
    const result = validateSpec(spec);
    expect(result.valid).toBe(true);
    expect(result.errors).toHaveLength(0);
  });

  it('missing openapi field fails', () => {
    const spec = generateOpenApiSpec([makeRoute()]);
    const invalid = { ...spec, openapi: '' };
    const result = validateSpec(invalid);
    expect(result.valid).toBe(false);
    expect(result.errors.some((e) => e.includes('openapi'))).toBe(true);
  });

  it('invalid openapi version fails', () => {
    const spec = generateOpenApiSpec([makeRoute()]);
    const invalid = { ...spec, openapi: '2.0' };
    const result = validateSpec(invalid);
    expect(result.valid).toBe(false);
    expect(result.errors.some((e) => e.includes('version'))).toBe(true);
  });

  it('empty paths fail', () => {
    const spec = generateOpenApiSpec([makeRoute()]);
    const invalid = { ...spec, paths: {} };
    const result = validateSpec(invalid);
    expect(result.valid).toBe(false);
    expect(result.errors.some((e) => e.includes('empty'))).toBe(true);
  });

  it('missing info fails', () => {
    const spec = generateOpenApiSpec([makeRoute()]);
    const invalid = { ...spec, info: undefined } as unknown as OpenApiSpec;
    const result = validateSpec(invalid);
    expect(result.valid).toBe(false);
    expect(result.errors.some((e) => e.includes('info'))).toBe(true);
  });

  it('missing info.title fails', () => {
    const spec = generateOpenApiSpec([makeRoute()]);
    const invalid = {
      ...spec,
      info: { ...spec.info, title: '' },
    };
    const result = validateSpec(invalid);
    expect(result.valid).toBe(false);
  });
});

